#include <iostream>
#include <fstream>
#include <string>
#include <vector>

using namespace std;

struct ConfigData {
    string key;
    string value;
};

ConfigData* readConfigFile(const char* filename) {
    ifstream file(filename);
    vector<ConfigData> configData;

    // Read the configuration file line by line
    string line;
    while (getline(file, line)) {
        // Split the line into key and value using '=' as a delimiter
        size_t pos = line.find('=');
        if (pos != string::npos) {
            ConfigData data;
            data.key = line.substr(0, pos);
            data.value = line.substr(pos + 1);
            configData.push_back(data);
        }
    }

    // Allocate memory for the configuration data
    ConfigData* configPtr = new ConfigData[configData.size()];
    for (int i = 0; i < configData.size(); i++) {
        configPtr[i] = configData[i];
    }

    return configPtr;
}